// Aggregate file system events in 30-second sliding window
const events = $input.item.json.events || [$input.item.json];

// Initialize aggregation metrics
const metrics = {
  hostname: events[0].hostname || 'UNKNOWN',
  username: events[0].username || 'UNKNOWN',
  detection_window_start: new Date(Date.now() - 30000).toISOString(),
  detection_window_end: new Date().toISOString(),
  detection_window_seconds: 30,

  file_operations: {
    total_operations: events.length,
    files_created: 0,
    files_modified: 0,
    files_renamed: 0,
    files_deleted: 0,
    avg_file_size_bytes: 0,
    total_bytes_written: 0,
    operations_per_second: 0,
    unique_directories_affected: new Set(),
    file_extensions_changed: [],
    suspicious_extensions: [],
    ransom_notes_created: [],
    entropy_analysis: {
      high_entropy_files: 0,
      avg_entropy: 0,
      entropy_increase_count: 0
    }
  },

  process_activity: {
    unique_processes: new Set(),
    high_io_processes: [],
    suspicious_commands: [],
    parent_child_chains: []
  },

  network_activity: {
    c2_connections: [],
    lateral_movement: [],
    smb_connections: 0,
    rdp_connections: 0
  },

  system_changes: {
    shadow_copy_deletions: false,
    boot_config_modifications: false,
    registry_modifications: [],
    service_installations: []
  }
};

// Known ransomware extensions
const ransomwareExtensions = [
  '.locked', '.encrypted', '.crypted', '.crypto', '.crypt', '.enc',
  '.lockbit', '.blackcat', '.royal', '.play', '.alphv', '.cl0p',
  '.cerber', '.locky', '.wannacry', '.petya', '.ryuk', '.maze'
];

// Known ransom note patterns
const ransomNotePatterns = [
  'README', 'HOW_TO_DECRYPT', 'DECRYPT_INSTRUCTIONS', 'RECOVERY',
  'YOUR_FILES', 'LOCKED', 'ENCRYPTED', 'RANSOM'
];

// Suspicious command patterns
const suspiciousCommands = [
  'vssadmin.exe delete shadows',
  'wmic shadowcopy delete',
  'bcdedit /set {default} recoveryenabled no',
  'bcdedit /set {default} bootstatuspolicy ignoreallfailures',
  'wbadmin delete catalog',
  'cipher /w:',
  'del /s /f /q'
];

// Process each file system event
let totalEntropy = 0;
let totalFileSize = 0;

events.forEach(event => {
  // Count operation types
  switch (event.operation?.toLowerCase()) {
    case 'create':
    case 'created':
      metrics.file_operations.files_created++;
      break;
    case 'modify':
    case 'modified':
    case 'write':
      metrics.file_operations.files_modified++;
      break;
    case 'rename':
    case 'renamed':
      metrics.file_operations.files_renamed++;

      // Check for suspicious extension changes
      const oldExt = event.old_path?.split('.').pop()?.toLowerCase();
      const newExt = event.new_path?.split('.').pop()?.toLowerCase();
      if (oldExt && newExt && oldExt !== newExt) {
        metrics.file_operations.file_extensions_changed.push({
          from: oldExt,
          to: newExt,
          path: event.new_path
        });

        if (ransomwareExtensions.includes(`.${newExt}`)) {
          metrics.file_operations.suspicious_extensions.push(`.${newExt}`);
        }
      }
      break;
    case 'delete':
    case 'deleted':
      metrics.file_operations.files_deleted++;
      break;
  }

  // Track directories
  const directory = event.path?.split('/').slice(0, -1).join('/') || 
                   event.path?.split('\\').slice(0, -1).join('\\');
  if (directory) {
    metrics.file_operations.unique_directories_affected.add(directory);
  }

  // Check for ransom notes
  const filename = event.path?.split('/').pop() || event.path?.split('\\').pop() || '';
  const filenameUpper = filename.toUpperCase();
  if (ransomNotePatterns.some(pattern => filenameUpper.includes(pattern)) &&
      (filename.endsWith('.txt') || filename.endsWith('.html') || filename.endsWith('.hta'))) {
    metrics.file_operations.ransom_notes_created.push(filename);
  }

  // Entropy analysis (high entropy = encrypted data)
  if (event.entropy !== undefined) {
    totalEntropy += event.entropy;
    if (event.entropy > 7.5) {
      metrics.file_operations.entropy_analysis.high_entropy_files++;
    }
    if (event.entropy_increase && event.entropy_increase > 1.0) {
      metrics.file_operations.entropy_analysis.entropy_increase_count++;
    }
  }

  // File size tracking
  if (event.size_bytes) {
    totalFileSize += event.size_bytes;
    metrics.file_operations.total_bytes_written += event.size_bytes;
  }

  // Process tracking
  if (event.process_name) {
    metrics.process_activity.unique_processes.add(event.process_name);

    // Track high I/O processes
    const existingProcess = metrics.process_activity.high_io_processes
      .find(p => p.pid === event.process_id);
    if (existingProcess) {
      existingProcess.operation_count++;
    } else if (event.io_rate_ops_per_sec > 100) {
      metrics.process_activity.high_io_processes.push({
        name: event.process_name,
        pid: event.process_id,
        operation_count: 1,
        io_rate: `${event.io_rate_ops_per_sec} ops/sec`
      });
    }
  }

  // Command line analysis
  if (event.command_line) {
    suspiciousCommands.forEach(pattern => {
      if (event.command_line.toLowerCase().includes(pattern.toLowerCase())) {
        metrics.process_activity.suspicious_commands.push(event.command_line);

        // Flag system changes
        if (pattern.includes('vssadmin') || pattern.includes('shadowcopy')) {
          metrics.system_changes.shadow_copy_deletions = true;
        }
        if (pattern.includes('bcdedit')) {
          metrics.system_changes.boot_config_modifications = true;
        }
      }
    });
  }

  // Network activity
  if (event.network_connection) {
    if (event.network_connection.protocol === 'SMB') {
      metrics.network_activity.smb_connections++;
      if (event.network_connection.target_host) {
        metrics.network_activity.lateral_movement.push({
          target: event.network_connection.target_host,
          protocol: 'SMB',
          status: event.network_connection.status || 'unknown'
        });
      }
    }
    if (event.network_connection.protocol === 'RDP') {
      metrics.network_activity.rdp_connections++;
    }

    // Check for C2 connections (external IPs)
    if (event.network_connection.remote_ip && 
        !event.network_connection.remote_ip.startsWith('10.') &&
        !event.network_connection.remote_ip.startsWith('192.168.') &&
        !event.network_connection.remote_ip.startsWith('172.16.')) {
      metrics.network_activity.c2_connections.push({
        ip: event.network_connection.remote_ip,
        port: event.network_connection.remote_port,
        country: event.network_connection.country || 'Unknown'
      });
    }
  }
});

// Calculate averages and rates
if (events.length > 0) {
  metrics.file_operations.avg_file_size_bytes = Math.round(totalFileSize / events.length);
  metrics.file_operations.operations_per_second = parseFloat((events.length / 30).toFixed(2));
  metrics.file_operations.entropy_analysis.avg_entropy = parseFloat(
    (totalEntropy / events.length).toFixed(2)
  );
}

// Convert Sets to Arrays for JSON serialization
metrics.file_operations.unique_directories_affected = 
  Array.from(metrics.file_operations.unique_directories_affected);
metrics.process_activity.unique_processes = 
  Array.from(metrics.process_activity.unique_processes);

// Remove duplicates
metrics.file_operations.suspicious_extensions = 
  [...new Set(metrics.file_operations.suspicious_extensions)];
metrics.process_activity.suspicious_commands = 
  [...new Set(metrics.process_activity.suspicious_commands)];
metrics.network_activity.c2_connections = 
  metrics.network_activity.c2_connections.filter((conn, index, self) =>
    index === self.findIndex(c => c.ip === conn.ip && c.port === conn.port)
  );

// Calculate initial risk indicators
const risk_indicators = {
  high_entropy_file_ratio: events.length > 0 ? 
    parseFloat((metrics.file_operations.entropy_analysis.high_entropy_files / events.length).toFixed(2)) : 0,
  rapid_file_modification: metrics.file_operations.operations_per_second > 8,
  suspicious_extension_detected: metrics.file_operations.suspicious_extensions.length > 0,
  ransom_note_detected: metrics.file_operations.ransom_notes_created.length > 0,
  shadow_copy_deletion: metrics.system_changes.shadow_copy_deletions,
  lateral_movement_detected: metrics.network_activity.lateral_movement.length > 0,
  c2_communication: metrics.network_activity.c2_connections.length > 0
};

metrics.risk_indicators = risk_indicators;
metrics.aggregation_timestamp = new Date().toISOString();
metrics.requires_ai_analysis = 
  risk_indicators.rapid_file_modification ||
  risk_indicators.suspicious_extension_detected ||
  risk_indicators.ransom_note_detected ||
  risk_indicators.shadow_copy_deletion;

return { json: { behaviorMetrics: metrics } };

