const aiResponse = $input.item.json;
let aiText = aiResponse.response || aiResponse.output || aiResponse.text || '';

// Handle Anthropic content array format
if (aiResponse.content && Array.isArray(aiResponse.content)) {
  aiText = aiResponse.content[0]?.text || '';
}

// Strip markdown code blocks
const cleanText = aiText
  .replace(/```json\s*/g, '')
  .replace(/```\s*/g, '')
  .trim();

let threatAnalysis;
try {
  threatAnalysis = JSON.parse(cleanText);
} catch (error) {
  throw new Error(`Failed to parse Claude AI threat analysis: ${error.message}. Raw: ${cleanText.substring(0, 200)}`);
}

// Pull behavior metrics from upstream
const behaviorMetrics = $('Aggregate File Operations (30s Window)').item.json.behaviorMetrics;

// Create comprehensive threat report
const threatReport = {
  detection_id: `RANSOMWARE-${Date.now()}-${Math.random().toString(36).substr(2, 8).toUpperCase()}`,
  detected_at: new Date().toISOString(),
  detection_source: 'Claude AI Ransomware Detection Engine v1.0',

  // System context
  affected_system: {
    hostname: behaviorMetrics.hostname,
    username: behaviorMetrics.username,
    detection_window: `${behaviorMetrics.detection_window_start} to ${behaviorMetrics.detection_window_end}`
  },

  // AI threat assessment
  threat_analysis: threatAnalysis.threat_assessment,
  ransomware_family: threatAnalysis.ransomware_family,
  behavioral_analysis: threatAnalysis.behavioral_analysis,
  mitre_attack_techniques: threatAnalysis.mitre_attack_techniques,

  // Raw behavior data
  behavior_metrics: behaviorMetrics,

  // Forensic evidence
  forensic_indicators: threatAnalysis.forensic_indicators,
  attack_timeline: threatAnalysis.attack_timeline,
  impact_assessment: threatAnalysis.impact_assessment,

  // Response decision
  recommended_action: threatAnalysis.recommended_action,
  isolation_required: threatAnalysis.recommended_action === 'ISOLATE_IMMEDIATELY',
  isolation_justification: threatAnalysis.isolation_justification,
  containment_priority: threatAnalysis.containment_priority,

  // Investigation guidance
  investigation_actions: threatAnalysis.investigation_priority_actions,
  analyst_notes: threatAnalysis.analyst_notes,

  // Confidence metrics
  confidence_level: threatAnalysis.threat_assessment.confidence_level,
  threat_score: threatAnalysis.threat_assessment.threat_score,
  false_positive_probability: threatAnalysis.false_positive_probability,

  // Status
  status: 'ANALYZED',
  next_action: threatAnalysis.threat_assessment.threat_score >= 75 ? 'INITIATE_ISOLATION' : 'MONITOR'
};

return { json: { threatReport } };

