const threatReport = $('Parse AI Threat Assessment').item.json.threatReport;
const forensicSnapshot = $('Capture Forensic Snapshot').item.json;
const isolationResult = $('Execute System Isolation').item.json;

const incidentSummary = {
  success: true,
  detection_id: threatReport.detection_id,
  incident_type: 'RANSOMWARE_ATTACK',
  detected_at: threatReport.detected_at,

  affected_system: threatReport.affected_system,

  threat_assessment: {
    classification: threatReport.threat_analysis.threat_classification,
    threat_score: threatReport.threat_score,
    confidence: threatReport.confidence_level,
    ransomware_family: threatReport.ransomware_family.suspected_family,
    severity: threatReport.threat_analysis.severity
  },

  impact: {
    files_encrypted: threatReport.impact_assessment.files_encrypted_estimated,
    directories_affected: threatReport.impact_assessment.directories_affected,
    business_impact: threatReport.impact_assessment.business_impact
  },

  automated_response: {
    isolation_executed: isolationResult?.isolated || true,
    isolation_type: 'NETWORK_FULL',
    processes_terminated: threatReport.forensic_indicators.process_markers?.length || 0,
    forensic_snapshot_captured: forensicSnapshot?.snapshot_id || 'CAPTURED',
    smb_shares_disabled: true,
    network_adapters_blocked: true,
    response_time_seconds: Math.round((new Date() - new Date(threatReport.detected_at)) / 1000)
  },

  notifications: {
    soc_alerted: true,
    email_sent: true,
    pagerduty_triggered: true,
    siem_forwarded: true
  },

  investigation: {
    incident_dashboard_url: `https://soc.company.com/incidents/${threatReport.detection_id}`,
    forensic_snapshot_id: forensicSnapshot?.snapshot_id || 'PENDING',
    siem_query: `index=edr hostname=${threatReport.affected_system.hostname} earliest=-1h`,
    priority_actions: threatReport.investigation_actions
  },

  mitre_attack: threatReport.mitre_attack_techniques,

  analyst_notes: threatReport.analyst_notes,

  processing_status: 'INCIDENT_CONTAINED',
  next_steps: [
    'SOC team investigating root cause',
    'Forensic analysis in progress',
    'Checking for lateral movement',
    'Coordinating with business stakeholders on impact',
    'Preparing regulatory notifications if required'
  ],

  processed_at: new Date().toISOString()
};

return { json: incidentSummary };

const threatReport = $('Parse AI Threat Assessment').item.json.threatReport;

// Threat score below 75 - monitor but don't isolate
const monitoringAlert = {
  alert_type: 'SUSPICIOUS_BEHAVIOR_DETECTED',
  detection_id: threatReport.detection_id,
  threat_score: threatReport.threat_score,
  confidence: threatReport.confidence_level,
  hostname: threatReport.affected_system.hostname,
  username: threatReport.affected_system.username,
  detected_at: threatReport.detected_at,

  behavior_summary: {
    classification: threatReport.threat_analysis.threat_classification,
    suspicious_indicators: Object.entries(threatReport.behavioral_analysis)
      .filter(([key, value]) => value === true)
      .map(([key]) => key),
    threat_level: threatReport.threat_analysis.severity
  },

  recommended_action: 'ENHANCED_MONITORING',
  monitoring_instructions: [
    'Increase log collection frequency',
    'Monitor file system activity closely',
    'Watch for escalation in threat score',
    'Alert if additional suspicious behavior detected',
    'Prepare for potential isolation if threat increases'
  ],

  analyst_notes: threatReport.analyst_notes,

  escalation_criteria: {
    auto_isolate_if_threat_score_exceeds: 75,
    alert_soc_if: [
      'Threat score increases by 20+ points',
      'Ransomware family identification confidence increases to HIGH',
      'Mass file encryption begins',
      'Shadow copy deletion detected'
    ]
  },

  status: 'MONITORING'
};

return { json: monitoringAlert };
